import{_ as e,C as p,o as t,c as l,ag as s,E as i}from"./chunks/framework.CAXxHpAX.js";const r="/images/chapter-04.svg",g=JSON.parse('{"title":"4. OLTP vs OLAP：大数据系统的第一分水岭","description":"解释业务交易和分析计算为什么会分化，以及 PostgreSQL 与 OLAP 系统如何分工。","frontmatter":{"title":"4. OLTP vs OLAP：大数据系统的第一分水岭","description":"解释业务交易和分析计算为什么会分化，以及 PostgreSQL 与 OLAP 系统如何分工。","prev":{"text":"3. PostgreSQL 大表能力：理解单机数据库边界","link":"/chapters/03-postgresql-large-tables"},"next":{"text":"5. 数据仓库建模：从表设计到分析建模","link":"/chapters/05-data-warehouse-modeling"}},"headers":[],"relativePath":"chapters/04-oltp-olap.md","filePath":"chapters/04-oltp-olap.md"}'),d={name:"chapters/04-oltp-olap.md"};function o(c,a,b,h,u,m){const n=p("Mermaid");return t(),l("div",null,[a[0]||(a[0]=s('<h1 id="_4-oltp-vs-olap-大数据系统的第一分水岭" tabindex="-1">4. OLTP vs OLAP：大数据系统的第一分水岭 <a class="header-anchor" href="#_4-oltp-vs-olap-大数据系统的第一分水岭" aria-label="Permalink to &quot;4. OLTP vs OLAP：大数据系统的第一分水岭&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">本章导读</p><p>解释业务交易和分析计算为什么会分化，以及 PostgreSQL 与 OLAP 系统如何分工。</p></div><p><img src="'+r+'" alt="OLTP vs OLAP：大数据系统的第一分水岭"></p><h2 id="本章阅读框架" tabindex="-1">本章阅读框架 <a class="header-anchor" href="#本章阅读框架" aria-label="Permalink to &quot;本章阅读框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阅读问题</th><th>本章回答方式</th></tr></thead><tbody><tr><td>这个问题为什么出现？</td><td>从业务增长、数据规模、系统目标或 AI 应用压力切入。</td></tr><tr><td>它解决什么问题？</td><td>提炼为一个核心判断，避免把概念写成孤立定义。</td></tr><tr><td>它不解决什么问题？</td><td>在机制解释和常见误区中说明边界，防止工具崇拜。</td></tr><tr><td>它在真实平台哪里出现？</td><td>放回 PostgreSQL、数仓、批流、OLAP、湖仓、向量、图和治理的演化链路。</td></tr><tr><td>读完要会做什么？</td><td>通过场景案例和实战任务转成可练习的判断。</td></tr></tbody></table>',5)),i(n,{code:"flowchart%20LR%0A%20%20P%5B%22PostgreSQL%20%E4%B8%9A%E5%8A%A1%E5%BA%93%22%5D%20--%3E%20O1%5B%22OLTP%3A%20%E9%AB%98%E9%A2%91%E5%B0%8F%E4%BA%8B%E5%8A%A1%20%2F%20%E5%BC%BA%E4%B8%80%E8%87%B4%22%5D%0A%20%20P%20--%3E%20O2%5B%22OLAP%3A%20%E5%A4%A7%E8%8C%83%E5%9B%B4%E6%89%AB%E6%8F%8F%20%2F%20%E8%81%9A%E5%90%88%E5%88%86%E6%9E%90%22%5D%0A%20%20O1%20--%3E%20A%5B%22%E4%B8%9A%E5%8A%A1%E6%AD%A3%E7%A1%AE%22%5D%0A%20%20O2%20--%3E%20B%5B%22%E5%88%86%E6%9E%90%E6%95%88%E7%8E%87%22%5D%0A"}),a[1]||(a[1]=s(`<p>PostgreSQL 可以支撑业务交易，也可以做一定规模分析。</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>但当业务增长后，一个数据库很难同时把两类目标做到极致：高频小事务和大范围复杂分析。</p><p>这就是 OLTP 和 OLAP 分化的根源。</p><p>在第 3 章中，我们看到 PostgreSQL 可以通过索引、分区、物化视图和执行计划分析继续支撑大表。但这些机制仍然工作在同一个数据库内部：业务交易、运营报表、临时分析和历史扫描都在争抢同一套 CPU、内存、I/O、锁和连接资源。</p><p>一个典型事故是：运营同学在工作日上午运行了一条过去一年订单明细 JOIN 商品、用户、支付和活动表的分析 SQL。查询本身没有错，但它扫描大量历史数据、占用缓存和 I/O，导致创建订单、查询订单详情、更新支付状态的接口延迟升高。</p><p>这时问题已经不是“再加一个索引能不能解决”，而是系统目标发生了冲突：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>业务系统希望每笔交易低延迟、强一致、稳定写入。</span></span>
<span class="line"><span>分析系统希望扫描大量历史数据、自由组合维度、批量计算指标。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><blockquote><p>OLTP 和 OLAP 不是两个时髦分类，而是两类负载目标的系统分工。</p></blockquote><p>OLTP 和 OLAP 的分化，本质上不是数据库产品分类，而是数据系统在读写模式、延迟目标、一致性目标、建模方式和团队协作上的分工。</p><p>OLTP 解决的是业务事实能否被可靠创建、修改和查询；OLAP 解决的是历史事实能否被高效扫描、聚合、分析和复用。它们都重要，但优化方向不同。试图让一个业务库长期承担所有交易和所有分析，通常会把两类目标都拖慢。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="一、oltp-面向业务交易" tabindex="-1">一、OLTP：面向业务交易 <a class="header-anchor" href="#一、oltp-面向业务交易" aria-label="Permalink to &quot;一、OLTP：面向业务交易&quot;">​</a></h3><p>OLTP 是 Online Transaction Processing，面向在线交易处理。</p><p>典型场景包括：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户注册</span></span>
<span class="line"><span>用户登录</span></span>
<span class="line"><span>商品查询</span></span>
<span class="line"><span>创建订单</span></span>
<span class="line"><span>支付更新</span></span>
<span class="line"><span>库存扣减</span></span>
<span class="line"><span>订单状态流转</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这些操作通常有几个特点：</p><ul><li>高频。</li><li>单次涉及数据范围小。</li><li>延迟要求低。</li><li>一致性要求高。</li><li>写入和更新频繁。</li><li>查询以点查和短查询为主。</li></ul><p>OLTP 系统更关注：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这笔订单是否可靠创建？</span></span>
<span class="line"><span>库存是否正确扣减？</span></span>
<span class="line"><span>支付状态是否准确更新？</span></span>
<span class="line"><span>两个用户并发操作是否会破坏一致性？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>PostgreSQL、MySQL、Oracle 都是典型 OLTP 数据库代表。</p><p>OLTP 的建模通常更强调规范化。用户、订单、商品、支付、库存会被拆成不同表，通过主键和外键表达关系，避免大量重复和更新异常。</p><h3 id="二、olap-面向数据分析" tabindex="-1">二、OLAP：面向数据分析 <a class="header-anchor" href="#二、olap-面向数据分析" aria-label="Permalink to &quot;二、OLAP：面向数据分析&quot;">​</a></h3><p>OLAP 是 Online Analytical Processing，面向在线分析处理。</p><p>典型场景包括：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>统计最近一年 GMV 趋势</span></span>
<span class="line"><span>按渠道、地区、类目分析销售额</span></span>
<span class="line"><span>计算用户留存和复购</span></span>
<span class="line"><span>分析转化漏斗</span></span>
<span class="line"><span>生成经营看板</span></span>
<span class="line"><span>对历史事件做多维聚合</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这些操作通常有几个特点：</p><ul><li>大范围扫描。</li><li>聚合计算多。</li><li>读多写少或批量写入。</li><li>查询涉及历史数据。</li><li>更关注吞吐和分析效率。</li><li>允许一定的数据延迟。</li></ul><p>OLAP 系统更关注：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>怎样更快扫描大量列？</span></span>
<span class="line"><span>怎样压缩历史数据？</span></span>
<span class="line"><span>怎样加速 GROUP BY？</span></span>
<span class="line"><span>怎样支持多维分析？</span></span>
<span class="line"><span>怎样避免分析任务影响业务交易？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>ClickHouse、Doris、Hive、Spark SQL、Trino 都是 OLAP 或分析计算体系中的代表。</p><p>OLAP 建模通常更强调分析效率。数据会被组织成事实表、维度表、宽表、聚合表或数仓分层。</p><h3 id="三、核心差异" tabindex="-1">三、核心差异 <a class="header-anchor" href="#三、核心差异" aria-label="Permalink to &quot;三、核心差异&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>OLTP</th><th>OLAP</th></tr></thead><tbody><tr><td>主要任务</td><td>业务交易</td><td>数据分析</td></tr><tr><td>查询模式</td><td>点查、短查询</td><td>大范围扫描、聚合</td></tr><tr><td>写入模式</td><td>高频小事务</td><td>批量写入、流式写入</td></tr><tr><td>一致性目标</td><td>强一致优先</td><td>分析可用性和吞吐优先</td></tr><tr><td>存储倾向</td><td>行存</td><td>列存</td></tr><tr><td>建模方式</td><td>规范化模型</td><td>星型模型、宽表、分层模型</td></tr><tr><td>代表系统</td><td>PostgreSQL / MySQL / Oracle</td><td>ClickHouse / Doris / Hive / Spark SQL / Trino</td></tr></tbody></table><p>行存适合 OLTP，因为一笔交易往往需要读取和更新同一行的多个字段。</p><p>列存适合 OLAP，因为分析经常只读取少数列，但要扫描大量行。例如统计 GMV 可能只需要 <code>created_at</code>、<code>order_status</code>、<code>total_amount</code>，不需要读取订单表所有字段。</p><h3 id="四、为什么业务库不能直接做所有大分析" tabindex="-1">四、为什么业务库不能直接做所有大分析？ <a class="header-anchor" href="#四、为什么业务库不能直接做所有大分析" aria-label="Permalink to &quot;四、为什么业务库不能直接做所有大分析？&quot;">​</a></h3><p>不是因为业务库不能分析。</p><p>而是因为长期把所有分析压在业务库上，会带来四类问题：</p><p>第一，资源冲突。</p><p>分析查询会大量扫描、排序、聚合，占用 CPU、内存和 I/O，影响在线交易延迟。</p><p>第二，模型冲突。</p><p>业务库强调规范化和一致修改，分析系统强调可读性、宽表、维度和指标口径。</p><p>第三，历史数据压力。</p><p>业务库需要稳定支撑当前业务，不应该无限承担多年历史明细的复杂分析。</p><p>第四，协作治理压力。</p><p>多个团队直接查业务库，会造成权限风险、口径不一致和查询成本不可控。</p><p>所以合理架构通常是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL / MySQL</span></span>
<span class="line"><span>  -&gt; ETL / CDC</span></span>
<span class="line"><span>  -&gt; 数仓 / OLAP / 湖仓</span></span>
<span class="line"><span>  -&gt; BI / 指标 / 数据应用</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="五、何时从-postgresql-迁移到-olap-系统" tabindex="-1">五、何时从 PostgreSQL 迁移到 OLAP 系统？ <a class="header-anchor" href="#五、何时从-postgresql-迁移到-olap-系统" aria-label="Permalink to &quot;五、何时从 PostgreSQL 迁移到 OLAP 系统？&quot;">​</a></h3><p>不是所有项目一开始都需要 ClickHouse、Doris 或 Spark。</p><p>可以先用 PostgreSQL 解决业务和中小规模分析。</p><p>当出现以下信号时，应考虑 OLAP 分离：</p><ul><li>报表查询开始影响业务接口。</li><li>历史扫描越来越频繁。</li><li>多维聚合越来越复杂。</li><li>数据需要跨多个业务系统融合。</li><li>指标口径需要统一管理。</li><li>数据量增长超过单机维护舒适区。</li><li>多个团队频繁直接查业务库。</li></ul><p>迁移不是把 PostgreSQL 扔掉，而是重新分工：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL</span></span>
<span class="line"><span>  -&gt; 可靠记录业务事实</span></span>
<span class="line"><span></span></span>
<span class="line"><span>OLAP / 数仓</span></span>
<span class="line"><span>  -&gt; 承担历史分析、指标生产和跨域查询</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="深度展开-oltp-olap-分化如何落到真实系统" tabindex="-1">深度展开：OLTP / OLAP 分化如何落到真实系统 <a class="header-anchor" href="#深度展开-oltp-olap-分化如何落到真实系统" aria-label="Permalink to &quot;深度展开：OLTP / OLAP 分化如何落到真实系统&quot;">​</a></h3><p>本节补齐本章的工程细节。阅读时不要只记住概念名称，而要把它放回“输入是什么、处理路径是什么、输出给谁、边界在哪里、如何验证”的链路中。</p><h4 id="一、它从什么问题开始" tabindex="-1">一、它从什么问题开始 <a class="header-anchor" href="#一、它从什么问题开始" aria-label="Permalink to &quot;一、它从什么问题开始&quot;">​</a></h4><p>业务交易和历史分析都重要，但它们对延迟、一致性、读写模式、数据模型和资源使用的要求不同。</p><p>这个问题通常不会以技术名词出现，而是以业务现象出现：报表变慢、指标不一致、实时看板延迟、RAG 召回不稳定、数据无法追溯、项目 Demo 无法验收。能不能把现象还原成系统问题，是本书要训练的第一层能力。</p><h4 id="二、输入数据和前置判断" tabindex="-1">二、输入数据和前置判断 <a class="header-anchor" href="#二、输入数据和前置判断" aria-label="Permalink to &quot;二、输入数据和前置判断&quot;">​</a></h4><p>输入是一套业务事实源，例如用户、订单、支付、库存、行为事件，以及来自运营、财务、增长和产品团队的分析需求。</p><p>在动手之前，至少要确认四件事：</p><table tabindex="0"><thead><tr><th>判断项</th><th>要回答的问题</th></tr></thead><tbody><tr><td>数据粒度</td><td>一行代表什么事实，是用户、订单、订单明细、事件、文件、Chunk，还是一条关系？</td></tr><tr><td>时间边界</td><td>使用创建时间、更新时间、支付时间、事件时间，还是处理时间？</td></tr><tr><td>状态边界</td><td>哪些状态算有效，哪些测试、取消、退款、重复或迟到数据要排除？</td></tr><tr><td>责任边界</td><td>这个环节负责记录事实、生产指标、加速查询、治理质量，还是服务 AI 应用？</td></tr></tbody></table><h4 id="三、处理路径" tabindex="-1">三、处理路径 <a class="header-anchor" href="#三、处理路径" aria-label="Permalink to &quot;三、处理路径&quot;">​</a></h4><p>处理路径是把业务写入保留在 OLTP 系统，把历史扫描、宽表建模、多维聚合和指标生产迁移到 OLAP 或数仓系统，再通过 ETL 或 CDC 连接两边。</p><p>这条路径应该能被写成可执行流程，而不是停留在术语解释。一个合格的设计至少要说明：数据从哪里来、经过哪些转换、写到哪里、谁消费、失败后如何重跑、结果如何校验。</p><h4 id="四、在真实平台中的位置" tabindex="-1">四、在真实平台中的位置 <a class="header-anchor" href="#四、在真实平台中的位置" aria-label="Permalink to &quot;四、在真实平台中的位置&quot;">​</a></h4><p>真实平台通常让 PostgreSQL 或 MySQL 承担强一致业务事实，让 ClickHouse、Doris、Hive、Spark、Trino 或湖仓承担分析事实。二者之间用调度、日志或变更流传递数据。</p><p>平台位置决定了它和前后系统的关系。不要孤立地问“这个技术好不好”，而要问：</p><ul><li>它继承了上一层什么问题？</li><li>它把什么复杂度转移给了下一层？</li><li>它的输出是否能被复用、追溯和治理？</li><li>它是否改变了数据粒度、延迟、一致性或权限边界？</li></ul><h4 id="五、边界和失败模式" tabindex="-1">五、边界和失败模式 <a class="header-anchor" href="#五、边界和失败模式" aria-label="Permalink to &quot;五、边界和失败模式&quot;">​</a></h4><p>OLAP 分离不是把所有查询都迁走。订单详情、用户资料、支付状态仍属于业务库；跨月趋势、渠道拆解、用户分群和指标口径才更适合分析系统。</p><p>常见失败信号可以这样检查：</p><table tabindex="0"><thead><tr><th>失败信号</th><th>应该追问什么</th></tr></thead><tbody><tr><td>运营查询拖慢下单接口</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>业务库里出现大量宽表和报表临时表</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>历史数据保留周期和业务库备份冲突</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>多个团队直接连业务库取数</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr></tbody></table><h4 id="六、可操作练习" tabindex="-1">六、可操作练习 <a class="header-anchor" href="#六、可操作练习" aria-label="Permalink to &quot;六、可操作练习&quot;">​</a></h4><p>把一个订单系统拆成 OLTP 查询清单和 OLAP 查询清单，说明每个查询为什么留在业务库或迁到分析库。</p><p>练习完成后不要只看“有没有跑通”，还要补一份复盘：</p><ul><li>输入数据是否足以支撑问题？</li><li>口径和边界是否写清楚？</li><li>结果能否被重复计算和对账？</li><li>如果数据量扩大 10 倍，瓶颈会出现在哪里？</li><li>如果接入下游 BI、RAG 或治理系统，还缺哪些元数据？</li></ul><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>本章是全书第一条系统分水岭。</p><p>第 1-3 章都还在 PostgreSQL 内部展开：表、约束、事务、SQL、大表、索引、分区、执行计划。到第 4 章，读者需要意识到：有些问题不是继续优化业务库就能优雅解决的，而是需要把交易处理和分析处理拆到不同系统中。</p><p>这一步会引出后续所有数据平台主题：</p><table tabindex="0"><thead><tr><th>后续章节</th><th>从 OLTP/OLAP 分化继承的问题</th></tr></thead><tbody><tr><td>数仓建模</td><td>业务库表结构不等于分析模型，需要事实表、维度表和指标口径</td></tr><tr><td>ETL / ELT</td><td>数据要从 OLTP 系统稳定进入分析系统</td></tr><tr><td>批处理</td><td>大规模历史数据加工需要分布式计算</td></tr><tr><td>实时处理</td><td>业务变更和事件需要低延迟进入分析链路</td></tr><tr><td>OLAP 数据库</td><td>多维聚合和交互式查询需要列式、预聚合、MPP 或本地向量化执行</td></tr><tr><td>湖仓</td><td>长期低成本存储和多引擎访问需要开放表格式和 Catalog</td></tr></tbody></table><p>因此，本章不是在劝读者“放弃 PostgreSQL”，而是在建立系统分工判断：PostgreSQL 继续作为业务事实源，分析系统承担历史分析、跨域建模和指标生产。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><p>以订单系统为例，业务链路和分析链路应该逐步拆开。</p><p>业务链路负责处理当前交易：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户下单</span></span>
<span class="line"><span>  -&gt; PostgreSQL 创建 orders / order_items</span></span>
<span class="line"><span>  -&gt; 支付成功后更新 payments / orders</span></span>
<span class="line"><span>  -&gt; 库存扣减</span></span>
<span class="line"><span>  -&gt; 订单状态流转</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这里最重要的是低延迟、一致性和失败可恢复。订单不能重复创建，库存不能扣错，支付状态不能丢。</p><p>分析链路负责处理历史事实：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL 订单、支付、商品、用户数据</span></span>
<span class="line"><span>  -&gt; ETL / CDC 同步</span></span>
<span class="line"><span>  -&gt; 数仓明细层和汇总层</span></span>
<span class="line"><span>  -&gt; ClickHouse / Doris / Trino / Spark SQL</span></span>
<span class="line"><span>  -&gt; BI 看板、经营分析、指标服务</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这里最重要的是大范围扫描、多维聚合、统一口径和可复用。运营可以分析最近一年 GMV，增长团队可以分析渠道转化，财务可以核对支付金额，算法团队可以生成用户特征。</p><p>这两个链路共享同一批业务事实，但不应该长期共享同一套查询负载。合理分工后，PostgreSQL 负责把事实写对，OLAP 和数仓负责把事实分析清楚。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：OLAP 比 OLTP 更高级。</strong></p><p>它们不是高低关系，而是目标不同。OLTP 负责业务正确，OLAP 负责分析效率。</p><p><strong>误区二：上了 ClickHouse 就不需要数仓建模。</strong></p><p>ClickHouse 是分析数据库，不会自动解决事实表、维度表、指标口径、数据质量和血缘治理。</p><p><strong>误区三：业务库不能做任何报表。</strong></p><p>业务库可以做轻量分析和运营查询，问题是不能无限承担所有复杂分析。</p><p><strong>误区四：OLTP 和 OLAP 分离只是性能优化。</strong></p><p>性能只是表层原因。更深层原因是负载目标、建模方式、团队协作和数据治理都不同。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>把以下查询分成 OLTP 和 OLAP：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查询某个用户最近 20 笔订单</span></span>
<span class="line"><span>更新订单支付状态</span></span>
<span class="line"><span>统计最近一年每日 GMV</span></span>
<span class="line"><span>计算用户 7 日留存</span></span>
<span class="line"><span>查询某个商品库存</span></span>
<span class="line"><span>统计商品销量排行榜</span></span>
<span class="line"><span>按城市和渠道分析新用户转化</span></span>
<span class="line"><span>创建订单并扣减库存</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>复盘问题：</p><ul><li>哪些查询需要低延迟和强一致？</li><li>哪些查询需要扫描大量历史数据？</li><li>哪些查询应该留在 PostgreSQL？</li><li>哪些查询应该进入 OLAP 或数仓？</li><li>哪些查询依赖统一指标口径？</li></ul><p>进阶任务：为其中两个 OLAP 查询设计迁移方案。</p><p>示例：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>统计最近一年每日 GMV</span></span>
<span class="line"><span>  源数据：orders、payments</span></span>
<span class="line"><span>  同步方式：按支付状态和支付时间同步到数仓</span></span>
<span class="line"><span>  明细模型：dwd_order_payment_detail</span></span>
<span class="line"><span>  汇总模型：dws_order_daily</span></span>
<span class="line"><span>  应用模型：ads_sales_dashboard</span></span>
<span class="line"><span>  查询引擎：ClickHouse / Doris / Trino</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>复盘时重点回答：</p><ul><li>哪些字段必须从业务库同步？</li><li>使用创建时间还是支付时间？</li><li>退款、取消、测试订单如何处理？</li><li>结果允许多大延迟？</li><li>如果报表数字和业务库临时查询不一致，应该如何追踪血缘和口径？</li></ul><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>OLTP 和 OLAP 的分化，是数据系统演化的第一条分水岭。</p><p>PostgreSQL 适合业务交易和中小规模分析，但当分析负载、数据规模和团队协作复杂度上升，系统就需要把分析能力迁移到数仓、OLAP 数据库、批处理或湖仓中。</p><p>下一章进入数据仓库建模。</p><p>因为把数据同步出去只是第一步，真正困难的是：如何把业务表重构成稳定、可分析、可复用的分析模型。</p>`,120))])}const L=e(d,[["render",o]]);export{g as __pageData,L as default};
